export interface AgentLog {
  /**
   * @displayName Agent Log
   * @description Unique system identifier - GUID generated by system
   * @uiConstraints NEVER create input fields for this ID
   */
  id: string;
  /**
   * @displayName Log Name
   * @description Human-readable record identifier
   * @validationRule Required for create/update operations
   */
  logName: string;
  /**
   * @displayName Agent Name
   * @validationRule Required for create/update operations
   */
  agentName: string;
  /**
   * @displayName Query Text
   * @validationRule Required for create/update operations
   */
  queryText: string;
  /**
   * @displayName Response Text
   */
  responseText?: string;
  /**
   * @displayName Session ID
   */
  sessionID?: string;
  /**
   * @displayName Source Description
   */
  sourceDescription?: string;
  /**
   * @displayName Timestamp
   * @validationRule Required for create/update operations
   */
  timestamp: string;
}

export const _AgentLog = 'AgentLog' as const;